function scenario(
  base: Omit<RecommendationQualityScenario, "humanReviewNotes" | "input"> & {
    preferredRitualStyles?: string[];
    avoidedRitualStyles?: string[];
    privateProfileKeys?: GenerateWeeklyBriefInput["privateProfileKeys"];
    excludedRitualPatternKeys?: string[];
    timingFacts?: GenerateWeeklyBriefInput["timingFacts"];
    computedTimingFacts?: GenerateWeeklyBriefInput["computedTimingFacts"];
    timingWindowCandidates?: GenerateWeeklyBriefInput["timingWindowCandidates"];
  },
): RecommendationQualityScenario {
  return {
    ...base,
    authoredOutput: authoredOutputExpectationsByScenarioId[base.id],
    humanReviewNotes: "Human review notes:",
    input: {
      currentDate: base.currentDate,
      capacityMode: base.currentRitualCheckIn.capacityMode,
      audience:
        base.currentRitualCheckIn.audience === "both_of_us" ? "together" : "either",
      currentRitualCheckIn: base.currentRitualCheckIn,
      profileInputs: base.profilePlaceholders ?? profilePlaceholders,
      privateProfileKeys:
        base.privateProfileKeys ??
        (base.currentRitualCheckIn.audience === "both_of_us"
          ? [
              "private_profile.practical_tending",
              "private_profile.beauty_warmth",
            ]
          : ["private_profile.practical_tending"]),
      preferredRitualStyles: base.preferredRitualStyles ?? [
        "home_tending",
        "plant_tending",
        "kitchen",
        "candle_or_light",
      ],
      avoidedRitualStyles: base.avoidedRitualStyles ?? [
        "shopping_required",
        "heavy_cleanup",
        "long_journaling",
        "elaborate_setup",
      ],
      excludedRitualPatternKeys: base.excludedRitualPatternKeys,
      timingFacts: base.timingFacts,
      computedTimingFacts: base.computedTimingFacts,
      timingWindowCandidates: base.timingWindowCandidates,
    },
  };
}

function planetSignFact(
  planet: "mercury" | "venus" | "saturn",
  sign: "virgo" | "leo" | "taurus",
): NonNullable<GenerateWeeklyBriefInput["computedTimingFacts"]>[number] {
  const degree = 13;

  return {
    id: `fixture.${planet}.${sign}`,
    type: "planet_sign",
    label: `${planet} in ${sign}`,
    exactIso: "2026-06-05T12:00:00.000Z",
    computedBy: "manual",
    confidence: "manual",
    planet,
    sign,
    degree,
    eclipticLongitudeDegrees: degree,
  };
}

